import{_ as s,C as t,o as d,c as h,j as e,a as n,E as i,a3 as m}from"./chunks/framework.CVjg771q.js";const P=JSON.parse('{"title":"坐忘论","description":"唐代司马承祯的修真名篇，以坐忘收心为入口，七阶次第归道。","frontmatter":{"title":"坐忘论","description":"唐代司马承祯的修真名篇，以坐忘收心为入口，七阶次第归道。","category":"guide","aliases":["坐忘论","zuowang lun"],"source":["坐忘论","司马承祯"]},"headers":[],"relativePath":"daoism/daoist-classics/zuowang-lun.md","filePath":"daoism/daoist-classics/zuowang-lun.md","lastUpdated":1777883327000}'),c={name:"daoism/daoist-classics/zuowang-lun.md"};function u(p,a,g,b,_,f){const o=t("DaoReadingPrelude"),r=t("DaoOriginalReading"),l=t("DaoKeywordCards");return d(),h("div",null,[a[0]||(a[0]=e("h1",{id:"坐忘论",tabindex:"-1"},[n("坐忘论 "),e("a",{class:"header-anchor",href:"#坐忘论","aria-label":'Permalink to "坐忘论"'},"​")],-1)),i(o,{title:"先看坐忘如何收心归道",summary:"坐忘论不是谈玄说妙的空论，而是从「敬信」到「得道」的七步实修路径。最适合的进入方式，是先通读七篇标题，感受其中「由外而内、由粗而精」的次第，再进入原文逐段体会。",points:[{label:"先通",text:"七篇顺序不是随意排的——敬信是根，得道是果。"},{label:"再体",text:"收心、真观、泰定三步是核心功夫。"},{label:"后归",text:"全篇终点不是神异，而是身心与道合一。"}],hint:"若是第一次读坐忘论，建议先把七篇标题与核心句读一遍，感受层层推进的力道。"}),a[1]||(a[1]=e("h2",{id:"【原典层】原文",tabindex:"-1"},[n("【原典层】原文 "),e("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),i(r,{paragraphs:["◎ 敬信一","信者道之根，敬者德之蒂。根深则道可长，蒂固则德可茂。","◎ 断缘二","断缘者，谓断有为俗事之缘也。弃事则形不劳，无为则心自安。恬简日就，尘累日薄，迹弥远俗，心弥近道。","◎ 收心三","夫心者，一身之主，百神之帅。静则生慧，动则生昏。","学道之初，要须安坐，收心离境，住无所有，不著一物，自入虚无，心乃合道。","◎ 简事四","夫人之生也，必营于事物。事物称万，不独委于一人。","知生之有分，不务分之所无；识事之有当，不任非当之事。","◎ 真观五","夫观者，智士之先鉴，能人之善察。","若以合境之心观境，终身不觉有恶；如将离境之心观境，方能了见是非。","◎ 泰定六","夫定者，尽俗之极地，致道之初基，习静之成功，持安之毕事。","形如槁木，心若死灰，无感无求，寂泊之至。无心于定，而无所不定，故曰泰定。","◎ 得道七","道者，神异之物，灵而有性，虚而无象，随迎莫测，影响莫求。","山有玉，草木以之不凋；人怀道，形体以之永固。"]}),a[2]||(a[2]=e("h2",{id:"【原典层】字词释义",tabindex:"-1"},[n("【原典层】字词释义 "),e("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),i(l,{title:"字词释义",items:[{term:"蒂",pinyin:["dì"],meaning:"花蒂之蒂，根深蒂固，喻根基牢固。"},{term:"恬",pinyin:["tián"],meaning:"恬简，安静简朴；恬淡之意。"},{term:"槁",pinyin:["gǎo"],meaning:"槁木，枯木。形如槁木喻身不动摇。"},{term:"寂",pinyin:["jì"],meaning:"寂泊，寂静淡泊；非死寂而是安定。"},{term:"营",pinyin:["yíng"],meaning:"此处指经营、操持事务。"}]}),a[3]||(a[3]=m('<h2 id="【解读层】导读" tabindex="-1">【解读层】导读 <a class="header-anchor" href="#【解读层】导读" aria-label="Permalink to &quot;【解读层】导读&quot;">​</a></h2><h3 id="象" tabindex="-1">象 <a class="header-anchor" href="#象" aria-label="Permalink to &quot;象&quot;">​</a></h3><p>坐忘论以一颗心为「象」——心是身之主，百神之帅。静则生慧，动则生昏。修行的起点不是外边找什么，而是先把这颗往外跑的心收回来。七篇次第如登阶：敬信是立住脚，断缘是卸包袱，收心是转过来，简事是放下来，真观是看清楚，泰定是站得稳，得道是自然到。</p><h3 id="理" tabindex="-1">理 <a class="header-anchor" href="#理" aria-label="Permalink to &quot;理&quot;">​</a></h3><p>全篇核心在「收心」与「离境」四个字。不是要消灭心，而是让心不追着外物跑——「不著一物，自入虚无，心乃合道」。这层理与道德经「致虚极，守静笃」、「为道日损」一脉相承。司马承祯把道家修心的路径，用七个阶梯讲得清清楚楚。</p><h3 id="用" tabindex="-1">用 <a class="header-anchor" href="#用" aria-label="Permalink to &quot;用&quot;">​</a></h3><p>坐忘不是逃避，而是一种收回心力、重新校准的方法。在心杂乱、事务缠、焦躁不安时，不必等大段独处才「修」，先试着在片刻间把心从外境收回来一点——不追念、不预演、不评判——这就是「收心」在日常里的用。从一分钟开始，慢慢延长。</p><h3 id="我的理解" tabindex="-1">我的理解 <a class="header-anchor" href="#我的理解" aria-label="Permalink to &quot;我的理解&quot;">​</a></h3><p>待梳理。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>坐忘论· 司马承祯</li><li>云笈七签收录版本</li></ul>',11))])}const q=s(c,[["render",u]]);export{P as __pageData,q as default};
